    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        SpyneDecimal(min_occurs=1),
        Unicode,
        Unicode,
        _returns=TransferResponse,
        _soap_action="http://financial.services.api/transferFunds",
        _operation_name="transferFunds",
    )
    def transferFunds(ctx, from_account_id, to_account_id, amount, currency, reference_note):
        """
        Transfer funds between two accounts.
        SOAPAction: http://financial.services.api/transferFunds
        """
        logger.info(
            f"transferFunds called: {from_account_id} -> {to_account_id}, "
            f"amount={amount}, currency={currency}, ref={reference_note}"
        )

        response = TransferResponse()
        response.from_account_id = from_account_id
        response.to_account_id = to_account_id
        response.amount = amount
        response.currency = currency or "USD"
        response.timestamp = datetime.utcnow()

        # Validate source account
        valid, msg = validate_account(from_account_id)
        if not valid:
            response.transaction_id = ""
            response.status_code = 404 if "not found" in msg else 403
            response.status_message = f"Source account error: {msg}"
            response.from_new_balance = Decimal("0.00")
            response.to_new_balance = Decimal("0.00")
            logger.warning(f"transferFunds failed: {response.status_message}")
            return response

        # Validate destination account
        valid, msg = validate_account(to_account_id)
        if not valid:
            response.transaction_id = ""
            response.status_code = 404 if "not found" in msg else 403
            response.status_message = f"Destination account error: {msg}"
            response.from_new_balance = Decimal("0.00")
            response.to_new_balance = Decimal("0.00")
            logger.warning(f"transferFunds failed: {response.status_message}")
            return response

        # Cannot transfer to same account
        if from_account_id == to_account_id:
            response.transaction_id = ""
            response.status_code = 400
            response.status_message = "Cannot transfer to the same account"
            response.from_new_balance = ACCOUNTS_DB[from_account_id]["balance"]
            response.to_new_balance = ACCOUNTS_DB[to_account_id]["balance"]
            logger.warning(f"transferFunds failed: same account transfer attempted")
            return response

        # Validate amount
        if amount is None or amount <= 0:
            response.transaction_id = ""
            response.status_code = 400
            response.status_message = "Transfer amount must be positive"
            response.from_new_balance = Decimal("0.00")
            response.to_new_balance = Decimal("0.00")
            logger.warning(f"transferFunds failed: invalid amount {amount}")
            return response

        # Check sufficient funds
        source_balance = ACCOUNTS_DB[from_account_id]["balance"]
        if source_balance < amount:
            response.transaction_id = ""
            response.status_code = 402
            response.status_message = (
                f"Insufficient funds. Available: {source_balance}, Requested: {amount}"
            )
            response.from_new_balance = source_balance
            response.to_new_balance = ACCOUNTS_DB[to_account_id]["balance"]
            logger.warning(f"transferFunds failed: insufficient funds in {from_account_id}")
            return response

        # Execute transfer
        ACCOUNTS_DB[from_account_id]["balance"] -= amount
        ACCOUNTS_DB[to_account_id]["balance"] += amount

        txn_id = generate_transaction_id()

        # Log transaction
        txn_record = {
            "transaction_id": txn_id,
            "from_account_id": from_account_id,
            "to_account_id": to_account_id,
            "amount": amount,
            "currency": currency or "USD",
            "reference_note": reference_note or "",
            "timestamp": datetime.utcnow(),
        }
        TRANSACTION_LOG.append(txn_record)

        response.transaction_id = txn_id
        response.status_code = 200
        response.status_message = "Transfer completed successfully"
        response.from_new_balance = ACCOUNTS_DB[from_account_id]["balance"]
        response.to_new_balance = ACCOUNTS_DB[to_account_id]["balance"]

        logger.info(
            f"transferFunds success: {txn_id}, "
            f"{from_account_id}({response.from_new_balance}) -> "
            f"{to_account_id}({response.to_new_balance})"
        )
        return response

